const norm = s => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\b(sa|sas|sarl|sasu|eurl|group|groupe|holding|france|se)\b/g, ' ').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
const slug = u => { const m = (u || '').toString().toLowerCase().match(/linkedin\.com\/company\/([^\/?#]+)/); return m ? m[1] : ''; };
const companies = $input.all().map(it => it.json);
const cibles = $('Airtable : Comptes Cibles').all().map(it => it.json);
const byName = new Map(), bySlug = new Map(), bySiren = new Map();
for (const c of companies) { const n = norm(c['Company Name']); if (n) byName.set(n, c); const s = slug(c['Linkedin Url']); if (s) bySlug.set(s, c); const si = (c['SIREN'] || '').toString().replace(/\D/g, ''); if (si) bySiren.set(si, c); }
const out = [];
for (const cb of cibles) {
  if ((cb['Qualif IA'] || '') !== 'Client final') continue;
  const name = (cb.Entreprise || '').toString().trim();
  const siren = (cb['SIREN / SIRET'] || '').toString().replace(/\D/g, '');
  const cslug = slug(cb['Page LinkedIn entreprise']);
  let match = null, by = '';
  if (siren && bySiren.has(siren)) { match = bySiren.get(siren); by = 'siren'; }
  else if (byName.has(norm(name))) { match = byName.get(norm(name)); by = 'nom'; }
  else if (cslug && bySlug.has(cslug)) { match = bySlug.get(cslug); by = 'linkedin'; }
  if (match) {
    const fill = [];
    if (siren && !((match['SIREN'] || '').toString().trim())) fill.push('SIREN');
    if (cslug && !((match['Linkedin Url'] || '').toString().trim())) fill.push('Linkedin Url');
    if ((cb.Ville || '') && !((match['Headquarters Location'] || '').toString().trim())) fill.push('Headquarters Location');
    out.push({ json: { decision: 'MATCH', cible: name, company_existante: match['Company Name'], matche_par: by, champs_a_remplir: fill.join(', ') || '(deja complet)' } });
  } else {
    out.push({ json: { decision: 'NOUVEAU', cible: name, company_existante: '', matche_par: '', champs_a_remplir: 'creation: Company Name + SIREN + Linkedin + Ville' } });
  }
}
const nMatch = out.filter(o => o.json.decision === 'MATCH').length;
const nNew = out.length - nMatch;
out.unshift({ json: { decision: '=== RESUME ===', cible: out.length + ' clients qualifies', company_existante: nMatch + ' MATCH / ' + nNew + ' NOUVEAU', matche_par: '', champs_a_remplir: 'AUCUNE ECRITURE - dry-run' } });
return out;
